/// <summary>
///Buttons are shown only if FDAutomation is enabled and the selected dimension attribute matches the configured Contract.
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(DimensionValueDetails, DimensionAttributeValue), FormDataSourceEventType::Activated)]
public static void DimensionAttributeValue_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();

    DimensionAttributeValue dimAttrValue = sender.cursor();
    ETGACFParameters        acfParameters = ETGACFParameters::find();
    DimensionAttribute      dimAttr       = DimensionAttribute::find(dimAttrValue.DimensionAttribute);

    FormButtonGroupControl  buttonImport = formRun.design().controlName(formControlStr(DimensionValueDetails, Import)) as FormButtonGroupControl;
    FormButtonGroupControl  buttonExport = formRun.design().controlName(formControlStr(DimensionValueDetails, Export)) as FormButtonGroupControl;

    if (ETGACFParameters::find().EnableContractFDAutomation)
    {
        if (dimAttr && dimAttr.Name == acfParameters.Contract)
        {
            buttonImport.visible(true);
            buttonExport.visible(true);
        }
        else
        {
            buttonImport.visible(false);
            buttonExport.visible(false);
        }
    }
    else
    {
        buttonImport.visible(false);
        buttonExport.visible(false);
    }
}
